package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatIsNullStringSetTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a CSVFormat instance using reflection to call the private constructor
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsNullStringSetWhenNullStringIsNull() throws Exception {
        // Using reflection to set private field nullString to null
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(csvFormat, null);

        assertFalse(csvFormat.isNullStringSet(), "Expected isNullStringSet to return false when nullString is null");
    }

    @Test
    public void testIsNullStringSetWhenNullStringIsNotNull() throws Exception {
        // Using reflection to set private field nullString to a non-null value
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(csvFormat, "NULL");

        assertTrue(csvFormat.isNullStringSet(), "Expected isNullStringSet to return true when nullString is not null");
    }
}
